import "../styles/Team.css";

export default function Team() {
  const centerMember = {
    name: "Your Name",
    role: "Founder / CEO",
    imgSrc: "/path-to-image/you.jpg",
  };

  const teamMembers = [
    { name: "John Doe", role: "Lead Designer", imgSrc: "/path/john.jpg" },
    { name: "Jane Smith", role: "Senior Developer", imgSrc: "/path/jane.jpg" },
    { name: "Emily Johnson", role: "Project Manager", imgSrc: "/path/emily.jpg" },
    { name: "Mike Brown", role: "UX Specialist", imgSrc: "/path/mike.jpg" },
    { name: "Sara Lee", role: "QA Engineer", imgSrc: "/path/sara.jpg" },
    { name: "David Kim", role: "DevOps Engineer", imgSrc: "/path/david.jpg" },
    { name: "Lily Adams", role: "Marketing Lead", imgSrc: "/path/lily.jpg" },
    { name: "Tom White", role: "Backend Developer", imgSrc: "/path/tom.jpg" },
    { name: "Rachel Green", role: "Content Strategist", imgSrc: "/path/rachel.jpg" },
    { name: "Chris Black", role: "Frontend Engineer", imgSrc: "/path/chris.jpg" },
  ];

  // Split members evenly
  const half = Math.ceil(teamMembers.length / 2);
  const leftMembers = teamMembers.slice(0, half);
  const rightMembers = teamMembers.slice(half);

  return (
    <section className="team-section">
      <h3>Meet the Team</h3>
      <div className="team-layout">
        {/* Left Scroll */}
        <div className="side-column scroll-column">
          <div className="scroll-wrapper">
            {[...leftMembers, ...leftMembers].map((member, idx) => (
              <div className="member-card" key={`left-${idx}`}>
                <img src={member.imgSrc} alt={member.name} />
                <p>{member.name}</p>
                <span>{member.role}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Center Profile */}
        <div className="center-column">
          <div className="center-profile">
            <img src={centerMember.imgSrc} alt={centerMember.name} />
            <h4>{centerMember.name}</h4>
            <p className="role">{centerMember.role}</p>
          </div>
        </div>

        {/* Right Scroll */}
        <div className="side-column scroll-column reverse">
          <div className="scroll-wrapper">
            {[...rightMembers, ...rightMembers].map((member, idx) => (
              <div className="member-card" key={`right-${idx}`}>
                <img src={member.imgSrc} alt={member.name} />
                <p>{member.name}</p>
                <span>{member.role}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
